'use client';

import { useToast } from '@/hooks/use-toast';
import React, { useState, useEffect, useMemo } from 'react';
import {
  MapPin,
  University,
  Rocket,
  Download,
  Calendar1,
  Building,
  Type,
  Plus,
  Gift,
  DollarSign,
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import EventCard from '@/components/ui/EventCard';
import { EventCategory } from '@/types';
import Link from 'next/link';
import { jsPDF } from 'jspdf';
import { Button } from '@/components/ui/button';
import { useDebounce } from 'use-debounce';
import { useAuth } from '@/context/AuthContext';
import Decorations from '@/components/ui/Decorations';
import Pagination from '@/components/ui/Pagination';
import { Loading } from '@/components/ui/Loading';
import SearchInput from '@/components/ui/SearchInput';
import { fetchEvents } from '@/api/events/events';
import { Card } from '@/components/ui/Card';
import { StatCard } from '@/components/ui/StatCard';
import { Check, X, Clock, Activity } from 'lucide-react';
import RoleChart from '@/components/admin/users/RoleChart';
import SignupTrendChart from '@/components/admin/users/SignupTrendChart';

// Charts removed to reuse Admin approach (no charts)

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: {
    opacity: 1,
    y: 0,
    transition: {
      duration: 0.5,
      ease: 'easeOut',
    },
  },
  hover: {
    scale: 1.02,
    transition: {
      duration: 0.3,
    },
  },
};

const AllEventsPage = ({ className }: React.HTMLAttributes<HTMLDivElement>) => {
  const { toast } = useToast();
  const { token } = useAuth();
  const [events, setEvents] = useState<EventCategory[]>([]);
  const [activeFilter, setActiveFilter] = useState<
    'all' | 'upcoming' | 'past' | 'pending' | 'approved' | 'rejected'
  >('all');
  const [isPrice, setIsPrice] = useState(false);
  const [isFree, setIsFree] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);
  // const [isLoading, setIsLoading] = useState(true);
  // حالة Pagination الجديدة

  const [currentPage, setCurrentPage] = useState(1); // حالة Pagination الجديدة
  const [totalPages, setTotalPages] = useState(0);
  const [totalItems, setTotalItems] = useState(0);
  const [eventsPerPage] = useState(6); // عدد الأحداث في كل صفحة
  const [loading, setLoading] = useState(false);

  // ===== Derived analytics =====
  const kpis = useMemo(() => {
    const total = events.length;
    const approved = events.filter((e) => e.status === 'approved').length;
    const rejected = events.filter((e) => e.status === 'rejected').length;
    const pending = events.filter((e) => e.status === 'pending').length;
    return [
      { title: 'Approved', value: approved, change: '+0%', icon: Check },
      { title: 'Rejected', value: rejected, change: '-0%', icon: X },
      { title: 'Pending', value: pending, change: '+0%', icon: Clock },
      { title: 'Total', value: total, change: '+0%', icon: Activity },
    ];
  }, [events]);

  // Bar: registrations per event
  const barData = useMemo(
    () =>
      (events || []).map((e) => ({
        name: e.title,
        value: Array.isArray(e.registeredUsers) ? e.registeredUsers.length : 0,
      })),
    [events]
  );

  // Pie: status distribution
  const roleSlices = useMemo(() => {
    return [
      { label: 'Approved', value: events.filter((e) => e.status === 'approved').length, color: '#16a34a' },
      { label: 'Pending', value: events.filter((e) => e.status === 'pending').length, color: '#f59e0b' },
      { label: 'Rejected', value: events.filter((e) => e.status === 'rejected').length, color: '#ef4444' },
    ];
  }, [events]);

  // Monthly trend: count events per month
  const trendData = useMemo(() => {
    const map = new Map<string, number>();
    (events || []).forEach((e) => {
      const d = new Date(e.date);
      if (isNaN(d.getTime())) return;
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`; // YYYY-MM
      map.set(key, (map.get(key) || 0) + 1);
    });
    // sort by key ascending and format label as MMM
    const entries = Array.from(map.entries()).sort((a, b) => (a[0] < b[0] ? -1 : 1));
    return entries.map(([ym, count]) => {
      const [y, m] = ym.split('-');
      const date = new Date(Number(y), Number(m) - 1, 1);
      const label = date.toLocaleString(undefined, { month: 'short' });
      return { label, value: count };
    });
  }, [events]);

  const generateReport = (event: EventCategory) => {
    const doc = new jsPDF();

    doc.setFontSize(16);
    doc.text('Booking Invoice', 20, 20);

    doc.setFontSize(12);
    doc.text(`Student Name: Test User`, 20, 40);
    doc.text(`Student Email: test@example.com`, 20, 50);

    doc.text(`Event Name: ${event.title}`, 20, 70);
    doc.text(`Location: ${event.location}`, 20, 80);
    doc.text(`Date: ${new Date(event.date).toLocaleDateString()}`, 20, 90);

    doc.text(`Registered: #${event.isRegistered}`, 20, 110);
    doc.text('Thank you for booking with us!', 20, 130);

    doc.save(`Invoice-${event.title}.pdf`);
  };

  const currentEvents = (events || [])?.filter((event) => {
    const matchesSearch = event.title
      ?.toLowerCase()
      .includes(debouncedQuery.toLowerCase());
    const matchesBasicFilter =
      activeFilter === 'all' ||
      (activeFilter === 'upcoming' && event.status === 'upcoming') ||
      (activeFilter === 'past' && event.status === 'past') ||
      (activeFilter === 'pending' && event.status === 'pending') ||
      (activeFilter === 'approved' && event.status === 'approved') ||
      (activeFilter === 'rejected' && event.status === 'rejected');

    const matchesPriceFilter =
      (!isPrice && !isFree) ||
      (isPrice && event?.price !== 0) ||
      (isFree && event?.price === 0);

    return matchesSearch && matchesBasicFilter && matchesPriceFilter;
  });

  useEffect(() => {
    fetchEvents({
      token,
      currentPage,
      eventsPerPage,
      activeFilter,
      role: 'host',
      toast,
      setLoading,
    }).then((data) => {
      setEvents(data.events);
      setTotalPages(data.totalPages);
      setTotalItems(data.totalItems);
    });
  }, [currentPage, activeFilter]);
  // تصفية الأحداث

  // تغيير الصفحة
  const paginate = (pageNumber: number) => setCurrentPage(pageNumber);

  // إعادة تعيين الصفحة إلى 1 عند تغيير الفلتر
  useEffect(() => {
    setCurrentPage(1);
  }, [activeFilter]);

  // إعادة تعيين فلاتر السعر عند تغيير الفلتر الأساسي
  useEffect(() => {
    setIsPrice(false);
    setIsFree(false);
  }, [activeFilter]);

  if (loading) {
    return <Loading />;
  }
  return (
    <>
      <main className='bg-white min-h-screen relative overflow-hidden'>
        <div className='max-w-6xl mx-auto px-4 relative'>
          {/* Stats Overview */}
          <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }} className='grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mt-8'>
            {kpis.map((k, i) => (
              <StatCard key={k.title} title={k.title} value={k.value} change={k.change} icon={k.icon as any} delay={i * 0.05} />
            ))}
          </motion.div>

          {/* Status Filter (Approved/Pending/Rejected/All) */}
          <div className='flex items-center gap-2 sm:gap-3 mt-6'>
            {(['all', 'approved', 'pending', 'rejected'] as const).map((f) => (
              <button
                key={f}
                onClick={() => {
                  setActiveFilter(f);
                  setCurrentPage(1);
                }}
                className={`relative px-4 py-2 rounded-full text-sm font-medium transition-all ring-1 ring-purple-200/60 hover:ring-purple-400/60 ${
                  activeFilter === f
                    ? 'bg-gradient-to-r from-purple-600 to-pink-600 text-white shadow'
                    : 'bg-white text-purple-700 hover:bg-purple-50'
                }`}
              >
                {f.charAt(0).toUpperCase() + f.slice(1)}
              </button>
            ))}
          </div>

          {/* Controls */}
          <motion.div
            className='flex flex-col lg:flex-row gap-4 items-stretch my-8'
            variants={itemVariants}
          >
            {/* Search Input */}
            <SearchInput
              name='Events'
              searchQuery={searchQuery}
              setSearchQuery={setSearchQuery}
              setCurrentPage={() => setCurrentPage(1)}
            />

            {/* Price/Free toggles */}
            <div className='flex gap-2 items-center'>
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => {
                  setIsFree(!isFree);
                  if (!isFree) setIsPrice(false);
                  setCurrentPage(1);
                }}
                className={`relative flex items-center gap-2 px-4 py-2 rounded-full border-2 transition-all duration-300
                  ${isFree ? 'border-purple-500/30 bg-purple-600 text-white' : 'border-white/10 bg-purple-900 text-white'}`}
              >
                <Gift className='h-4 w-4' />
                <span className='text-sm'>Free</span>
              </motion.button>
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => {
                  setIsPrice(!isPrice);
                  if (!isPrice) setIsFree(false);
                  setCurrentPage(1);
                }}
                className={`relative flex items-center gap-2 px-4 py-2 rounded-full border-2 transition-all duration-300
                  ${isPrice ? 'border-purple-500/30 bg-purple-600 text-white' : 'border-white/10 bg-purple-900 text-white'}`}
              >
                <DollarSign className='h-4 w-4' />
                <span className='text-sm'>Price</span>
              </motion.button>
            </div>
          </motion.div>

          {currentEvents.length > 0 ? (
            <motion.div
              className='grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8'
              initial='hidden'
              animate='visible'
              variants={{
                hidden: { opacity: 0 },
                visible: {
                  opacity: 1,
                  transition: {
                    staggerChildren: 0.1,
                    delayChildren: 0.2,
                  },
                },
              }}
            >
              <AnimatePresence>
                {currentEvents?.map((event) => {
                  return (
                    <motion.div
                      key={event._id}
                      variants={itemVariants}
                      whileHover={{ y: -5, transition: { type: 'spring', stiffness: 300 } }}
                      className='relative group'
                    >
                      <EventCard
                        event={event}
                        href={`/host/events/${event._id}`}
                        className='transition-all duration-300 group-hover:shadow-xl group-hover:shadow-purple-500/20 group-hover:border-cyan-400/30'
                        role='host'
                        actionsMode='menu'
                        onDownloadInvoice={() => generateReport(event)}
                      />
                    </motion.div>
                  );
                })}
              </AnimatePresence>
            </motion.div>
          ) : (
            <motion.div
              className='text-center py-30 space-y-4'
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
            >
              <div className='text-xl font-bold'>No events found</div>
              <p className='text-muted-foreground'>
                {searchQuery
                  ? 'Try a different search term'
                  : 'Create your first event to get started'}
              </p>
              {/* Create Event */}
              <Button className='bg-gradient-to-r from-purple-800 to-pink-700'>
                <Plus className='text-white'></Plus>
                <Link href='/create'>Create Events</Link>
              </Button>
            </motion.div>
          )}

          {/* Pagination Controls */}
          {currentEvents.length > 0 && (
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              totalItems={totalItems}
              paginate={paginate}
            />
          )}
        </div>
        <Decorations />
      </main>
      ;
    </>
  );
};
export default AllEventsPage;
